SELECT ID AS id, USER_NAME AS userName, USER_NICKNAME AS userNickname, USER_INTRO AS userIntro, USER_JOB AS userJob, USER_ADDRESS AS userAddress, USER_EMAIL AS userEmail, USER_PHONE_NUM AS userPhoneNum, USER_EXP AS userExp, USER_PROFILE AS userProfile, USER_CREATE_AT AS userCreateAt
FROM TBL_USER
WHERE ID = #{userId}

SELECT COUNT(ID)
FROM TBL_SOCIAL_USER
WHERE USER_ID = #{userId}

SELECT COUNT(ID)
FROM TBL_USER
WHERE USER_NICKNAME = #{userNickname} AND ID != #{userId}

