SET USER_NICKNAME = #{requestDTO.userNickname}, USER_INTRO = #{requestDTO.userIntro}, USER_JOB = #{requestDTO.userJob}, USER_ADDRESS = #{requestDTO.userAddress}
WHERE ID = #{userId}

UPDATE TBL_USER
SET USER_PHONE_NUM = #{requestDTO.userPhoneNum}
WHERE ID = #{userId}

UPDATE TBL_USER
SET USER_PROFILE = #{userProfile}
WHERE ID = #{userId}

UPDATE TBL_USER
SET USER_PROFILE = 'default.jpg'
WHERE ID = #{userId}

